/**
 * Register — Bloque de Concorde (Voyager DS)
 *
 * Página de registro (Header guest + fondo blanco):
 *   · Heading — SVG exacto exportado de Figma (746×57), sin card detrás,
 *     primer elemento del contenido (apoyado directo sobre el fondo blanco)
 *   · PersonalDataCard — card "Datos Personales" (766×~307), grid de 6 campos
 *   · BillingCard — card "Quiero Recibir" (766×~149): toggle Boleta/Factura + RUC
 *   · Nota "Importante" — sin card detrás
 *   · Banner placeholder "Términos y Condiciones" (766×288)
 *   · TermsAcceptance — 3 checkboxes + botón "Sigamos" (deshabilitado hasta
 *     marcar las 3), sin card detrás
 *   · Banner placeholder "Centro de Ayuda" (766×120)
 */

import type { CSSProperties, JSX } from "react";
import AppHeader from "../../header/desktop/Header";
import PersonalDataCard from "./PersonalDataCard";
import BillingCard from "./BillingCard";
import TermsAcceptance from "./TermsAcceptance";
import { REGISTER_WIDTH, REGISTER_HEIGHT } from "./dimensions";

export { REGISTER_WIDTH, REGISTER_HEIGHT } from "./dimensions";

export interface RegisterProps {
  /** Renderiza el AppHeader interno. `false` cuando el visor lo dibuja aparte. Default `true`. */
  renderHeader?: boolean;
  className?: string;
}

/**
 * ImportantNotice — nota "Importante:" + lista de avisos, sin card detrás.
 * Reusada tal cual por Register (desktop) y RegisterMobile.
 */
export function ImportantNotice(): JSX.Element {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
      <p style={{ margin: 0, fontSize: 15, fontWeight: 700, color: "#3B1782" }}>Importante:</p>
      <ul style={{ margin: 0, padding: "0 0 0 20px", display: "flex", flexDirection: "column", gap: 4, listStyleType: "disc", listStylePosition: "outside" }}>
        <li style={{ margin: 0, fontSize: 14, lineHeight: "20px", color: "#3B1782" }}>
          Debes leer nuestras <strong>Condiciones y Términos</strong> antes de registrarte.
        </li>
        <li style={{ margin: 0, fontSize: 14, lineHeight: "20px", color: "#3B1782" }}>
          Tu DNI es obligatorio en todo proceso de compra - venta.
        </li>
      </ul>
    </div>
  );
}

// Banner placeholder gris — mismo estilo usado en Login/Zona/Homepage.
function placeholderBanner(height: number): CSSProperties {
  return {
    width: 766,
    height,
    boxSizing: "border-box",
    borderRadius: 8,
    background: "#E9EAEC",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: 13,
    fontWeight: 600,
    letterSpacing: "0.06em",
    color: "#9AA1AC",
  };
}

