export default function Register({ renderHeader = true, className = "" }: RegisterProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="register"
      style={{
        width: REGISTER_WIDTH,
        minHeight: REGISTER_HEIGHT,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      {renderHeader ? <AppHeader width={REGISTER_WIDTH} /> : null}

      <div style={{ flex: 1, padding: "24px 16px", display: "flex", flexDirection: "column", gap: 16 }}>
        {/* Heading — primer elemento, sin card detrás (apoyado directo en el fondo blanco) */}
        <RegisterHeading />

        {/* Card "Datos Personales" */}
        <PersonalDataCard />

        {/* Card "Quiero Recibir" — toggle Boleta/Factura + RUC */}
        <BillingCard />

        {/* Nota "Importante" — sin card detrás, texto directo sobre el fondo blanco */}
        <ImportantNotice />

        {/* Banner placeholder "Términos y Condiciones" */}
        <div data-slot="terms-banner" style={placeholderBanner(288)}>TÉRMINOS Y CONDICIONES</div>

        {/* Checklist de aceptación + botón "Sigamos" — sin card detrás */}
        <TermsAcceptance />

        {/* Banner placeholder "Centro de Ayuda" */}
        <div data-slot="help-banner" style={placeholderBanner(120)}>CENTRO DE AYUDA</div>
      </div>
    </div>
  );
}
